SELECT COUNT(*) AS QUANTIDADE FROM SERVIDOR_TCC ST JOIN SERVIDOR S ON S.PK_SIAPE = ST.FK_SIAPE JOIN TCC T ON T.PK = ST.FK_TCC WHERE S.GENERO = 'MASCULINO' AND LOWER(T.CURSO) LIKE LOWER('%engenharia civil%') AND LOWER(T.CAMPUS) LIKE LOWER('%formosa%') AND T.TIPO = 'TCC (TRABALHO DE CONCLUSAO DE CURSO)' AND T.ANO_LETIVO >= (CAST(strftime('%Y', 'now') AS INTEGER) - 4)